// ─── Import Helpers ───────────────────────────────────────────────────────────

// The source spreadsheet uses PROJ__ as the header for what we call PROJ_NUM
const IMPORT_COL_MAP = { 'PROJ__': 'PROJ_NUM' };

// ─── Flexible Import Utilities ───────────────────────────────────────────────

function normalizeHeader(h) {
  return String(h).toUpperCase().trim().replace(/[\s_]+/g, '_');
}

function tokenOverlapScore(a, b) {
  const tokA = normalizeHeader(a).split('_').filter(Boolean);
  const tokB = normalizeHeader(b).split('_').filter(Boolean);
  if (!tokA.length || !tokB.length) return 0;
  const setB = new Set(tokB);
  const matches = tokA.filter(t => setB.has(t)).length;
  return matches / Math.max(tokA.length, tokB.length);
}

function autoMapColumns(sourceHeaders) {
  const result = {};
  const usedTargets = new Set();
  const normalizedPipeline = {};
  PIPELINE_FIELDS.forEach(f => { normalizedPipeline[normalizeHeader(f)] = f; });

  // Build reverse alias map: normalizedAlias → field
  const aliasMap = {};
  for (const [field, aliases] of Object.entries(COLUMN_ALIASES)) {
    for (const alias of aliases) {
      aliasMap[normalizeHeader(alias)] = field;
    }
  }

  // Tier 1: Exact match (normalized)
  for (const src of sourceHeaders) {
    const norm = normalizeHeader(src);
    const exact = normalizedPipeline[norm];
    if (exact && !usedTargets.has(exact)) {
      result[src] = { target: exact, confidence: 'exact' };
      usedTargets.add(exact);
    }
  }

  // Tier 2: Alias lookup
  for (const src of sourceHeaders) {
    if (result[src]) continue;
    const norm = normalizeHeader(src);
    const aliased = aliasMap[norm];
    if (aliased && !usedTargets.has(aliased)) {
      result[src] = { target: aliased, confidence: 'alias' };
      usedTargets.add(aliased);
    }
  }

  // Tier 3: Fuzzy token overlap (score >= 0.5)
  for (const src of sourceHeaders) {
    if (result[src]) continue;
    let bestField = null, bestScore = 0;
    // Check against PIPELINE_FIELDS
    for (const field of PIPELINE_FIELDS) {
      if (usedTargets.has(field)) continue;
      const score = tokenOverlapScore(src, field);
      if (score > bestScore) { bestScore = score; bestField = field; }
    }
    // Also check against COLUMN_REGISTRY labels
    for (const [key, reg] of Object.entries(COLUMN_REGISTRY)) {
      if (!PIPELINE_FIELDS.includes(key) || usedTargets.has(key)) continue;
      if (reg.label) {
        const score = tokenOverlapScore(src, reg.label);
        if (score > bestScore) { bestScore = score; bestField = key; }
      }
    }
    if (bestField && bestScore >= 0.5) {
      result[src] = { target: bestField, confidence: 'fuzzy' };
      usedTargets.add(bestField);
    }
  }

  return result;
}

function isFastPathImport(sourceHeaders) {
  const mapped = autoMapColumns(sourceHeaders);
  const exactOrAlias = Object.values(mapped).filter(m => m.confidence === 'exact' || m.confidence === 'alias').length;
  return exactOrAlias >= PIPELINE_FIELDS.length * 0.8;
}

function validateEnumValues(rows, columnMapping) {
  const issues = {};
  // Build target→source column map
  const targetToSource = {};
  for (const [src, mapping] of Object.entries(columnMapping)) {
    if (mapping.target && mapping.target !== '(Skip)') {
      targetToSource[mapping.target] = src;
    }
  }

  for (const [field, validator] of Object.entries(ENUM_FIELD_VALIDATORS)) {
    const srcCol = targetToSource[field];
    if (!srcCol) continue;

    const valuesUpper = new Set(validator.values.map(v => v.toUpperCase()));
    const aliasMap = {};
    for (const [alias, canonical] of Object.entries(validator.aliases)) {
      aliasMap[alias.toUpperCase()] = canonical;
    }

    const mismatches = {};
    for (const row of rows) {
      const raw = String(row[srcCol] || '').trim();
      if (!raw) continue;
      const upper = raw.toUpperCase();
      if (valuesUpper.has(upper)) continue;
      if (aliasMap[upper]) continue; // alias will auto-resolve
      if (!mismatches[raw]) mismatches[raw] = { count: 0, suggestion: null };
      mismatches[raw].count++;
    }

    // Try fuzzy matching for suggestions
    for (const [val, info] of Object.entries(mismatches)) {
      const upper = val.toUpperCase();
      // Check aliases first
      if (aliasMap[upper]) {
        info.suggestion = aliasMap[upper];
        continue;
      }
      // Fuzzy match against valid values
      let bestVal = null, bestScore = 0;
      for (const valid of validator.values) {
        const score = tokenOverlapScore(val, valid);
        if (score > bestScore) { bestScore = score; bestVal = valid; }
      }
      if (bestVal && bestScore >= 0.4) info.suggestion = bestVal;
    }

    if (Object.keys(mismatches).length > 0) {
      issues[field] = { mismatches, validValues: validator.values };
    }
  }
  return issues;
}

function cleanNumericValues(rows, columnMapping) {
  const targetToSource = {};
  for (const [src, mapping] of Object.entries(columnMapping)) {
    if (mapping.target && mapping.target !== '(Skip)') {
      targetToSource[mapping.target] = src;
    }
  }

  const numericIssues = {};
  const cleanedRows = rows.map(row => {
    const newRow = { ...row };
    for (const numField of NUMERIC_IMPORT_FIELDS) {
      const srcCol = targetToSource[numField];
      if (!srcCol || newRow[srcCol] === undefined) continue;
      const raw = String(newRow[srcCol]).trim();
      if (!raw) continue;
      // Strip $, commas, whitespace
      const cleaned = raw.replace(/[$,\s]/g, '');
      if (cleaned !== raw) newRow[srcCol] = cleaned;
      // Check if still non-numeric
      if (cleaned && isNaN(Number(cleaned))) {
        if (!numericIssues[numField]) numericIssues[numField] = {};
        if (!numericIssues[numField][raw]) numericIssues[numField][raw] = 0;
        numericIssues[numField][raw]++;
      }
    }
    return newRow;
  });
  return { cleanedRows, numericIssues };
}

function applyValueCorrections(rows, columnMapping, corrections) {
  if (!corrections || !Object.keys(corrections).length) return rows;
  const targetToSource = {};
  for (const [src, mapping] of Object.entries(columnMapping)) {
    if (mapping.target && mapping.target !== '(Skip)') {
      targetToSource[mapping.target] = src;
    }
  }

  return rows.map(row => {
    const newRow = { ...row };
    for (const [targetField, corrMap] of Object.entries(corrections)) {
      const srcCol = targetToSource[targetField];
      if (!srcCol) continue;
      const raw = String(newRow[srcCol] || '').trim();
      if (corrMap[raw] !== undefined) {
        newRow[srcCol] = corrMap[raw];
      }
    }
    return newRow;
  });
}

function applyColumnMapping(rawRows, columnMapping) {
  return rawRows.map(row => {
    const mapped = {};
    for (const [srcCol, mapping] of Object.entries(columnMapping)) {
      if (!mapping.target || mapping.target === '(Skip)') continue;
      mapped[mapping.target] = row[srcCol];
    }
    return mapped;
  });
}

// ─── Original Import Helpers ─────────────────────────────────────────────────

function normalizeDate(v) {
  if (!v) return '';
  // Excel serial number (days since 1900-01-01, with the 1900 leap-year bug)
  if (typeof v === 'number') {
    const epoch = new Date(1899, 11, 30);
    const d = new Date(epoch.getTime() + v * 86400000);
    return d.toISOString().slice(0, 10);
  }
  // JS Date object (SheetJS cellDates mode)
  if (v instanceof Date) {
    return v.toISOString().slice(0, 10);
  }
  // String — try to parse and return ISO date
  const d = new Date(String(v));
  if (!isNaN(d)) return d.toISOString().slice(0, 10);
  return '';
}

function inferExpenseType(projType, detail) {
  const s = ((projType || '') + ' ' + (detail || '')).toUpperCase();
  if (s.includes('DIGITAL') || s.includes('BANNER') || s.includes('SOCIAL MEDIA')) return 'Digital_Marketing';
  if (s.includes('TELEMARKETING')) return 'Agent_Leads';
  return 'Direct_Mail';
}

function mapBlueSheetClient(clientDesc) {
  if (!clientDesc) return 'Other';
  const upper = clientDesc.toUpperCase();
  const match = BLUE_SHEET_CLIENTS.find(c => upper.includes(c.toUpperCase()));
  // Also check common abbreviations
  if (match) return match;
  if (upper.includes('ALUMNI')) return 'Alumni';
  if (upper.includes('AOPA')) return 'AOPA';
  if (upper.includes('ASME')) return 'ASME';
  if (upper.includes('IEEE')) return 'IEEE';
  if (upper.includes('MOAA')) return 'MOAA';
  if (upper.includes('CALBAR')) return 'CalBar';
  if (upper.includes('NYSUT')) return 'NYSUT';
  if (upper.includes('PGA')) return 'PGA';
  if (upper.includes('AMBA')) return 'AMBA Legacy';
  if (upper.includes('MERCER')) return 'Mercer Other';
  return 'Other';
}

function mapChannel(projType) {
  if (!projType) return 'Other';
  const upper = String(projType).toUpperCase().trim();
  // Check Email BEFORE Direct Mail — "EMAIL" contains "MAIL"
  const patterns = [
    { channel: 'Email', keys: ['EMAIL','EBLAST','E-BLAST'] },
    { channel: 'Direct Mail', keys: ['MAIL','MAILING','DM','REMAIL'] },
    { channel: 'Print', keys: ['PRINT','MAGAZINE','MAG','BROCHURE','INSERT'] },
    { channel: 'Digital', keys: ['DIGITAL','PAID','BANNER','SOCIAL','DISPLAY','PPC','SEM','ONLINE'] },
  ];
  for (const p of patterns) {
    if (p.keys.some(k => upper.includes(k))) return p.channel;
  }
  return 'Other';
}

function mapChannelInd(val) {
  if (!val) return '';
  const upper = String(val).toUpperCase().trim();
  // Full names pass through
  if (CHANNELS.includes(upper)) return upper;
  // Keyword / abbreviation lookup
  const patterns = [
    { channel: 'DIRECT MAIL', keys: ['DM','D','M','MAIL','DIRECT'] },
    { channel: 'PAID DIGITAL', keys: ['PD','P','DIGITAL','PAID','BANNER','SOCIAL'] },
    { channel: 'EMAIL', keys: ['EM','E','EMAIL'] },
    { channel: 'TELESALES', keys: ['TS','T','TELE','TELESALES','TELEMARKETING'] },
    { channel: 'ECOMMERCE', keys: ['EC','ECOMM','ECOMMERCE'] },
  ];
  for (const p of patterns) {
    if (p.keys.includes(upper)) return p.channel;
  }
  // Substring match for longer values
  for (const p of patterns) {
    if (p.keys.some(k => k.length > 2 && upper.includes(k))) return p.channel;
  }
  return val;
}

function processImportedRows(rawRows, startId) {
  return rawRows.map((raw, idx) => {
    // Map columns (handle PROJ__ -> PROJ_NUM etc.)
    const mapped = {};
    Object.entries(raw).forEach(([key, val]) => {
      const k = IMPORT_COL_MAP[key] || key;
      mapped[k] = val;
    });

    const cost = Number(mapped.NEW_TOTAL_COST) || 0;
    const tap = Number(mapped.TAP) || 0;
    const mailMonth = Number(mapped.MAIL_MONTH) || 1;
    const expType = inferExpenseType(mapped.PROJ_TYPE, mapped.DETAIL);
    const product = mapped.PRODUCT || '';

    // Build monthly budget: full cost in MAIL_MONTH, zeros elsewhere
    const monthly = Array(12).fill(0);
    if (mailMonth >= 1 && mailMonth <= 12) monthly[mailMonth - 1] = cost;

    return {
      // Pipeline fields with numeric coercion where needed
      TEAM: mapped.TEAM || '',
      NEW_TEAM: mapped.NEW_TEAM || '',
      TEAM_DESC: mapped.TEAM_DESC || '',
      CLIENT_DESC: mapped.CLIENT_DESC || '',
      PLAN_CODE: mapped.PLAN_CODE || '',
      CLIENT: mapped.CLIENT || '',
      PROD: mapped.PROD || '',
      SYSTEM: mapped.SYSTEM || '',
      ADMIN_IND: mapped.ADMIN_IND || '',
      CHANNEL_IND: mapChannelInd(mapped.CHANNEL_IND),
      TEST_IND: mapped.TEST_IND || '',
      PROJ_NUM: mapped.PROJ_NUM || `IMP-${String(startId + idx).padStart(4, '0')}`,
      OPUS: mapped.OPUS || '',
      POLICY: mapped.POLICY || '',
      AE: mapped.AE || '',
      MAIL_DATE: normalizeDate(mapped.MAIL_DATE),
      IDENTIFIER: mapped.IDENTIFIER || '',
      MUTANT: mapped.MUTANT || '',
      YEAR: Number(mapped.YEAR) || 2026,
      QTR: mapped.QTR || '',
      PROJ_TYPE: mapped.PROJ_TYPE || '',
      PRODUCT: product,
      DETAIL: mapped.DETAIL || '',
      GANG_ID: mapped.GANG_ID || '',
      LOB: mapped.LOB || '',
      CARRIER: mapped.CARRIER || '',
      COMM_TYPE: mapped.COMM_TYPE || '',
      MAIL_MONTH: mailMonth,
      MAIL_DAY: Number(mapped.MAIL_DAY) || 1,
      LEAD_GEN: mapped.LEAD_GEN || '',
      LEAD_RATE: mapped.LEAD_RATE || 0,
      PROJ_STATUS: mapped.PROJ_STATUS || 'NOT STARTED',
      MAIL_QTY: Number(mapped.MAIL_QTY) || 0,
      GROSS: Number(mapped.GROSS) || 0,
      GROSS_APP: Number(mapped.GROSS_APP) || 0,
      PEND_APP: Number(mapped.PEND_APP) || 0,
      ISSUED: Number(mapped.ISSUED) || 0,
      REJECTED: Number(mapped.REJECTED) || 0,
      NET: Number(mapped.NET) || 0,
      NET_APP: Number(mapped.NET_APP) || 0,
      AAP: Number(mapped.AAP) || 0,
      TAP: tap,
      PAYRATE: mapped.PAYRATE || 0,
      COMM: Number(mapped.COMM) || 0,
      FEE_NET_APP: Number(mapped.FEE_NET_APP) || 0,
      EXPENSE_REIMBURSEMENT: Number(mapped.EXPENSE_REIMBURSEMENT) || 0,
      PROD_CPM: mapped.PROD_CPM || '0.00',
      C_TAP: tap > 0 ? cost / tap : 0,
      CFT_DIRECTOR: mapped.CFT_DIRECTOR || '',
      RISK_CODE: mapped.RISK_CODE || '',
      PA_ISSUED: mapped.PA_ISSUED || '',
      PA_APPROVED: mapped.PA_APPROVED || '',
      DROPPED_IND: mapped.DROPPED_IND || '',
      TOTAL_PO_AMOUNT: Number(mapped.TOTAL_PO_AMOUNT) || 0,
      NEW_BY_CARR_TOTAL: Number(mapped.NEW_BY_CARR_TOTAL) || 0,
      NEW_ALL_CARR_TOTAL: Number(mapped.NEW_ALL_CARR_TOTAL) || 0,
      NEW_AMBA_TOTAL: Number(mapped.NEW_AMBA_TOTAL) || 0,
      MERCER_TOTAL: Number(mapped.MERCER_TOTAL) || 0,
      NEW_TOTAL_COST: cost,
      // Auto-generated app-level fields
      id: startId + idx,
      _approvalStatus: 'Draft',
      _blueSheetVersion: 'MOM Pipeline',
      _expenseType: expType,
      _specificExpense: GL_MAP[expType] || '65110',
      _blueSheetClient: mapBlueSheetClient(mapped.CLIENT_DESC),
      _blueSheetProduct: PRODUCT_MAP[product] || product,
      _monthlyBudget: monthly,
      _channel: mapChannel(mapped.PROJ_TYPE),
    };
  });
}

