function MonthlyTapCard({ data }) {
  const monthly = useMemo(() => {
    const byMonth = Array(12).fill(0);
    for (const r of data) {
      if (!r.MAIL_DATE || !r.TAP) continue;
      const d = new Date(r.MAIL_DATE + 'T00:00:00');
      if (!isNaN(d)) byMonth[d.getMonth()] += Number(r.TAP) || 0;
    }
    return byMonth;
  }, [data]);
  const max = Math.max(...monthly, 1);

  return (
    <div className="summary-card monthly-tap-card">
      <div className="label">TAP by Month</div>
      <div className="monthly-tap-chart">
        {monthly.map((val, i) => (
          <div className="monthly-tap-col" key={i}>
            <div className="monthly-tap-bar-wrap">
              <div className="monthly-tap-bar" style={{ height: `${(val / max) * 100}%` }} title={fmtMoney(val)} />
            </div>
            <div className="monthly-tap-label">{MONTHS[i]}</div>
            <div className="monthly-tap-val">{val >= 1000 ? `${(val / 1000).toFixed(0)}k` : val > 0 ? fmtMoney(val) : ''}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

function SummaryCards({ data }) {
  const budgetRows = data.filter(r => r.IDENTIFIER === 'BUDGET');
  const actualRows = data.filter(r => r.IDENTIFIER === 'ACTUAL');
  const budgetTAP = _.sumBy(budgetRows, 'TAP');
  const actualTAP = _.sumBy(actualRows, 'TAP');
  const budgetCost = _.sumBy(budgetRows, 'NEW_TOTAL_COST');
  const actualCost = _.sumBy(actualRows, 'NEW_TOTAL_COST');
  const budgetCTAP = budgetTAP > 0 ? budgetCost / budgetTAP : 0;
  const actualCTAP = actualTAP > 0 ? actualCost / actualTAP : 0;
  const totalCost = _.sumBy(data, 'NEW_TOTAL_COST');
  const approved = data.filter(r => r._approvalStatus === 'Approved').length;
  const pending = data.filter(r => r._approvalStatus === 'Pending Review').length;

  const cards = [
    { label: 'Budget TAP', value: fmtMoney(budgetTAP), sub: `${budgetRows.length} budget records` },
    { label: 'Actual TAP', value: fmtMoney(actualTAP), sub: `${actualRows.length} actual records` },
    { label: 'Budget C/TAP', value: budgetCTAP.toFixed(3), sub: fmtMoney(budgetCost) + ' total cost', cls: ctapClass(budgetCTAP) },
    { label: 'Actual C/TAP', value: actualCTAP.toFixed(3), sub: fmtMoney(actualCost) + ' total cost', cls: ctapClass(actualCTAP) },
    { label: 'Total Cost', value: fmtMoney(totalCost), sub: `${data.length} campaigns` },
    { label: 'Approvals', value: `${approved}/${data.length}`, sub: `${pending} pending review` },
  ];
  return (
    <div className="summary-cards">
      <MonthlyTapCard data={data} />
      {cards.map((c, i) => (
        <div className="summary-card" key={i}>
          <div className="label">{c.label}</div>
          <div className={`value ${c.cls || ''}`}>{c.value}</div>
          <div className="sub">{c.sub}</div>
        </div>
      ))}
    </div>
  );
}

function YearMultiSelect({ selected, onChange, years }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);
  const toggle = (yr) => {
    const next = new Set(selected);
    next.has(yr) ? next.delete(yr) : next.add(yr);
    onChange(next);
  };
  const label = selected.size === 0 ? 'All Years' : selected.size === years.length ? 'All Years' : [...selected].sort().join(', ');
  return (
    <div className="year-multi-wrap" ref={ref}>
      <button className="year-multi-btn" onClick={() => setOpen(!open)}>{label} ▾</button>
      {open && (
        <div className="year-multi-dropdown">
          <div className="year-multi-option" onClick={() => onChange(new Set())}>
            <input type="checkbox" checked={selected.size === 0} readOnly /> All Years
          </div>
          {years.map(yr => (
            <div key={yr} className="year-multi-option" onClick={() => toggle(yr)}>
              <input type="checkbox" checked={selected.has(yr)} readOnly /> {yr}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function ChannelMultiSelect({ selected, onChange, channels }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);
  const toggle = (ch) => {
    const next = new Set(selected);
    next.has(ch) ? next.delete(ch) : next.add(ch);
    onChange(next);
  };
  const label = selected.size === 0 ? 'All Channels' : selected.size === channels.length ? 'All Channels' : [...selected].sort().join(', ');
  return (
    <div className="year-multi-wrap" ref={ref}>
      <button className="year-multi-btn" onClick={() => setOpen(!open)}>{label} ▾</button>
      {open && (
        <div className="year-multi-dropdown">
          <div className="year-multi-option" onClick={() => onChange(new Set())}>
            <input type="checkbox" checked={selected.size === 0} readOnly /> All Channels
          </div>
          {channels.map(ch => (
            <div key={ch} className="year-multi-option" onClick={() => toggle(ch)}>
              <input type="checkbox" checked={selected.has(ch)} readOnly /> {ch}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function FilterBar({ filters, setFilters, data }) {
  const set = (k, v) => setFilters(prev => ({ ...prev, [k]: v }));
  // Derive unique values from actual data for client and channel
  const uniqueYears = useMemo(() => _.sortBy(_.uniq(data.map(r => r.YEAR).filter(Boolean)).map(String)), [data]);
  const uniqueTeams = useMemo(() => _.sortBy(_.uniq(data.map(r => r.TEAM_DESC).filter(Boolean))), [data]);
  const uniqueClients = useMemo(() => _.sortBy(_.uniq(data.map(r => r.CLIENT_DESC).filter(Boolean))), [data]);
  const uniqueChannels = useMemo(() => _.sortBy(_.uniq(data.map(r => r._channel).filter(Boolean))), [data]);
  const uniqueChannelDetails = useMemo(() => _.sortBy(_.uniq(data.map(r => r.PROJ_TYPE).filter(Boolean))), [data]);
  const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return (
    <div className="filter-bar">
      <select value={filters.identifier} onChange={e => set('identifier', e.target.value)}>
        <option value="">All Identifiers</option>
        {IDENTIFIERS.map(v => <option key={v}>{v}</option>)}
      </select>
      <YearMultiSelect selected={filters.years} onChange={(yrs) => set('years', yrs)} years={uniqueYears} />
      <select value={filters.product} onChange={e => set('product', e.target.value)}>
        <option value="">All Products</option>
        {PRODUCTS.map(v => <option key={v}>{v}</option>)}
      </select>
      <ChannelMultiSelect selected={filters.channels} onChange={(chs) => set('channels', chs)} channels={uniqueChannels} />
      <select value={filters.channelDetail} onChange={e => set('channelDetail', e.target.value)}>
        <option value="">All Channel Details</option>
        {uniqueChannelDetails.map(v => <option key={v}>{v}</option>)}
      </select>
      <select value={filters.month} onChange={e => set('month', e.target.value)}>
        <option value="">All Months</option>
        {MONTH_NAMES.map((name, i) => <option key={i + 1} value={i + 1}>{name}</option>)}
      </select>
      <select value={filters.client} onChange={e => set('client', e.target.value)}>
        <option value="">All Clients</option>
        {uniqueClients.map(v => <option key={v}>{v}</option>)}
      </select>
      <select value={filters.approval} onChange={e => set('approval', e.target.value)}>
        <option value="">All Statuses</option>
        {APPROVAL_STATUSES.map(v => <option key={v}>{v}</option>)}
      </select>
      <select value={filters.team} onChange={e => set('team', e.target.value)}>
        <option value="">All Teams</option>
        {uniqueTeams.map(v => <option key={v}>{v}</option>)}
      </select>
      <div className="filter-spacer" />
      <input type="text" placeholder="Search campaigns..." value={filters.search} onChange={e => set('search', e.target.value)} />
    </div>
  );
}

